/* ===== TEMPLATE GALLERY (LOCAL, SELF-CONTAINED) ===== */
const TemplateGalleryPanel = React.memo(({
  items,
  onApply,
  format,
  isOpen,   // 👈 NEW PROP
  onToggle  // 👈 NEW PROP
}: {
  items: TemplateSpec[];
  onApply: (tpl: TemplateSpec, opts?: { targetFormat?: Format }) => void;
  format: Format;
  isOpen?: boolean;
  onToggle?: () => void;
}) => {
  const INITIAL_VISIBLE_TEMPLATES = 4;
  const [q, setQ] = React.useState('');
  const deferredQ = React.useDeferredValue(q);
  const [tag, setTag] = React.useState<string>('All');
  const [visibleCount, setVisibleCount] = React.useState(INITIAL_VISIBLE_TEMPLATES);
  const [pendingTemplateId, setPendingTemplateId] = React.useState<string | null>(null);

  const itemsWithTags = React.useMemo(
    () => items.map((t) => ({ ...t, normalizedTags: canonicalizeTemplateTags(t.tags) })),
    [items]
  );

  const allTags = React.useMemo(() => {
    const s = new Set<string>();
    itemsWithTags.forEach((t) => t.normalizedTags.forEach((x) => s.add(x)));

    const ordered = TAG_ORDER.filter((x) => s.has(x));
    const extra = Array.from(s).filter((x) => !TAG_ORDER_SET.has(x)).sort();
    return ["All", ...ordered, ...extra];
  }, [itemsWithTags]);

  const filtered = React.useMemo(() => {
    return itemsWithTags.filter((t) => {
      const okTag = tag === "All" || t.normalizedTags.includes(tag);
      const okQ = !deferredQ || t.label.toLowerCase().includes(deferredQ.toLowerCase());
      return okTag && okQ;
    });
  }, [itemsWithTags, deferredQ, tag]);

  React.useEffect(() => {
    setVisibleCount(INITIAL_VISIBLE_TEMPLATES);
  }, [tag, deferredQ, INITIAL_VISIBLE_TEMPLATES]);

  const visible = React.useMemo(
    () => filtered.slice(0, visibleCount),
    [filtered, visibleCount]
  );

  return (
    <Collapsible
      title="Template Gallery"
      storageKey="p:templates"
      isOpen={isOpen}     // 👈 PASS TO COLLAPSIBLE
      onToggle={onToggle} // 👈 PASS TO COLLAPSIBLE
      titleClassName={isOpen ? "text-amber-400" : ""}
      right={
        <input
          type="text"
          placeholder="Search…"
          value={q}
          onChange={(e) => setQ(e.target.value)}
          className="px-2 py-1 rounded-md text-xs border border-neutral-700 bg-neutral-900/80"
          style={{ width: 140 }}
        />
      }
    >
      <div className="mb-2 flex flex-wrap gap-2">
        {allTags.map(t => (
          <Chip key={t} small active={tag === t} onClick={() => setTag(t)}>
            {t}
          </Chip>
        ))}
      </div>

      <div className="grid grid-cols-2 gap-3">
        {visible.map(t => (
          <div
            key={t.id}
            className="rounded-lg overflow-hidden border border-neutral-700 bg-neutral-900/60"
          >
            <div className="relative">
              <img
                src={t.preview}
                alt={t.label}
                className="w-full h-[120px] object-cover block"
                draggable={false}
              />
              <div className="absolute left-2 top-2 flex gap-1 flex-wrap">
                {t.normalizedTags.slice(0, 2).map((x) => (
                  <span
                    key={x}
                    className="text-[10px] px-2 py-[2px] rounded-full bg-black/50 border border-white/10"
                  >
                    {x}
                  </span>
                ))}
              </div>
            </div>

            <div className="p-2 flex items-center justify-between gap-2">
              <div className="text-[12px] font-semibold">{t.label}</div>
              <button
                type="button"
                className="text-[12px] px-2 py-1 rounded-md border border-indigo-400/40 bg-indigo-600/20 hover:bg-indigo-600/30 focus-ring"
                disabled={pendingTemplateId === t.id}
                onClick={() => {
                  flushSync(() => {
                    setPendingTemplateId(t.id);
                  });
                  runAfterPaintAndYield(() => {
                    try {
                      onApply(t, { targetFormat: format });
                    } finally {
                      setPendingTemplateId(null);
                    }
                  });
                }}
              >
                {pendingTemplateId === t.id ? "Applying..." : "Apply"}
              </button>
            </div>
          </div>
        ))}
      </div>
      {filtered.length > visibleCount && (
        <div className="mt-3 grid place-items-center">
          <button
            type="button"
            className="rounded-lg border border-amber-300/25 bg-amber-300/10 px-3 py-1 text-xs text-amber-100 hover:bg-amber-300/15"
            onClick={() => setVisibleCount(filtered.length)}
          >
            <span className="inline-flex items-center gap-1 animate-pulse [animation-duration:4.2s] [animation-timing-function:ease-in-out]">
              View more templates
              <span aria-hidden="true">↓</span>
            </span>
          </button>
        </div>
      )}
    </Collapsible>
  );
});
TemplateGalleryPanel.displayName = 'TemplateGalleryPanel';

const BackgroundGalleryPanel = React.memo(({
  items,
  onApply,
  isOpen,
  onToggle,
}: {
  items: ReadonlyArray<{
    id: string;
    name: string;
    src: string;
  }>;
  onApply: (src: string) => void;
  isOpen?: boolean;
  onToggle?: () => void;
}) => {
  const INITIAL_VISIBLE_BACKGROUNDS = 4;
  const [visibleCount, setVisibleCount] = React.useState(INITIAL_VISIBLE_BACKGROUNDS);
  const [pendingBackgroundId, setPendingBackgroundId] = React.useState<string | null>(null);
  const visible = React.useMemo(
    () => items.slice(0, visibleCount),
    [items, visibleCount]
  );

  React.useEffect(() => {
    setVisibleCount(INITIAL_VISIBLE_BACKGROUNDS);
  }, [items]);

  return (
    <Collapsible
      title="Backgrounds"
      storageKey="p:dj-backgrounds"
      isOpen={isOpen}
      onToggle={onToggle}
      titleClassName={isOpen ? "text-amber-400" : ""}
    >
      <div className="grid grid-cols-2 gap-3">
        {visible.map((background) => (
          <div
            key={background.id}
            className="overflow-hidden rounded-lg border border-neutral-700 bg-neutral-900/60"
          >
            <img
              src={background.src}
              alt={background.name}
              className="block h-[120px] w-full object-cover"
              draggable={false}
            />
            <div className="flex items-center justify-between gap-2 p-2">
              <div className="text-[12px] font-semibold">{background.name}</div>
              <button
                type="button"
                className="rounded-md border border-indigo-400/40 bg-indigo-600/20 px-2 py-1 text-[12px] hover:bg-indigo-600/30 focus-ring"
                disabled={pendingBackgroundId === background.id}
                onClick={() => {
                  flushSync(() => {
                    setPendingBackgroundId(background.id);
                  });
                  runAfterPaintAndYield(() => {
                    try {
                      onApply(background.src);
                    } finally {
                      setPendingBackgroundId(null);
                    }
                  });
                }}
              >
                {pendingBackgroundId === background.id ? "Applying..." : "Apply"}
              </button>
            </div>
          </div>
        ))}
      </div>
      {items.length > visibleCount && (
        <div className="mt-3 grid place-items-center">
          <button
            type="button"
            className="rounded-lg border border-amber-300/25 bg-amber-300/10 px-3 py-1 text-xs text-amber-100 hover:bg-amber-300/15"
            onClick={() => setVisibleCount(items.length)}
          >
            <span className="inline-flex items-center gap-1 animate-pulse [animation-duration:4.2s] [animation-timing-function:ease-in-out]">
              View more backgrounds
              <span aria-hidden="true">↓</span>
            </span>
          </button>
        </div>
      )}
    </Collapsible>
  );
});
BackgroundGalleryPanel.displayName = 'BackgroundGalleryPanel';


