 const { baseW, baseH } = React.useMemo(() => {
  if (!pNatW || !pNatH) {
    return {
      baseW: 100,
      baseH: 100,
    };
  }
  const r = pNatW / pNatH;
  const maxW = 100;
  const maxH = 100;
  const maxR = maxW / maxH;

  return r >= maxR
    ? { baseW: maxW,      baseH: maxW / r }
    : { baseW: maxH * r,  baseH: maxH     };
}, [format, pNatW, pNatH]);

