    function normalizePortraitFor(fmt: Format, px: number, py: number, ps: number) {
    const w = 100;
    const h = 100;


      const x = clamp(px, 0, 100 - w);
      const y = clamp(py, 0, 100 - h);
      const s = Math.min(ps, 1.5);

      return { x, y, s };
    }

