// Save current design under a name (localStorage)
function saveDesign(name: string) {
  if (isStarterPlan) {
    alert('Project save is not available on Starter.');
    return;
  }
  if (!name || !name.trim()) { alert('Please name the design'); return; }
  const data = exportDesignJSON();
  const thumb = captureThumb();
  const payload = { v: 1, data, thumb: thumb ?? null, updatedAt: Date.now() };

  try {
    localStorage.setItem(`nf:design:${name}`, JSON.stringify(payload));

    const idx = readIndex();
    if (!idx.includes(name)) {
      idx.unshift(name);
      writeIndex(idx.slice(0, 200)); // keep last 200
    }
  } catch {
    alert('Save failed (localStorage full?)');
  }
}

// Load design by name (from localStorage)
function loadDesign(name: string) {
  try {
    const raw = localStorage.getItem(`nf:design:${name}`);
    if (!raw) { alert('Design not found'); return; }
    const j = JSON.parse(raw);
    if (!j || j.v !== 1 || !j.data) { alert('Corrupt design'); return; }
    importDesignJSON(j.data);
  } catch { alert('Load failed'); }
}

// List saved design names (newest first)
function listDesignNames(): string[] {
  return readIndex();
}

// Delete saved design
function deleteDesign(name: string) {
  try {
    localStorage.removeItem(`nf:design:${name}`);
    writeIndex(readIndex().filter(n => n !== name));
  } catch {}
}

function downloadBlob(filename: string, blob: Blob) {
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  a.rel = 'noopener';
  document.body.appendChild(a);
  a.click();
  requestAnimationFrame(() => {
    try { document.body.removeChild(a); } catch {}
    URL.revokeObjectURL(url);
  });
}




// ===== CLEAN EXPORT (PNG + JPG) — no UI, correct fonts =====

// ===== EXPORT: PNG (fonts + hide UI) =====
function twoRaf(): Promise<void> {
  return new Promise((r) =>
    requestAnimationFrame(() => requestAnimationFrame(() => r()))
  );
}

const EXPORT_DPI = 300;
const PNG_SIGNATURE = new Uint8Array([137, 80, 78, 71, 13, 10, 26, 10]);
const CRC32_TABLE = (() => {
  const table = new Uint32Array(256);
  for (let i = 0; i < 256; i++) {
    let c = i;
    for (let bit = 0; bit < 8; bit++) {
      c = (c & 1) !== 0 ? 0xedb88320 ^ (c >>> 1) : c >>> 1;
    }
    table[i] = c >>> 0;
  }
  return table;
})();

function readUint32BE(bytes: Uint8Array, offset: number) {
  return (
    ((bytes[offset] ?? 0) << 24) |
    ((bytes[offset + 1] ?? 0) << 16) |
    ((bytes[offset + 2] ?? 0) << 8) |
    (bytes[offset + 3] ?? 0)
  ) >>> 0;
}

function writeUint32BE(target: Uint8Array, offset: number, value: number) {
  target[offset] = (value >>> 24) & 0xff;
  target[offset + 1] = (value >>> 16) & 0xff;
  target[offset + 2] = (value >>> 8) & 0xff;
  target[offset + 3] = value & 0xff;
}

function concatByteArrays(parts: Uint8Array[]) {
  const total = parts.reduce((sum, part) => sum + part.length, 0);
  const out = new Uint8Array(total);
  let offset = 0;
  for (const part of parts) {
    out.set(part, offset);
    offset += part.length;
  }
  return out;
}

function crc32(bytes: Uint8Array) {
  let crc = 0xffffffff;
  for (let i = 0; i < bytes.length; i++) {
    crc = CRC32_TABLE[(crc ^ bytes[i]) & 0xff] ^ (crc >>> 8);
  }
  return (crc ^ 0xffffffff) >>> 0;
}

function buildPngChunk(type: string, data: Uint8Array) {
  const typeBytes = new TextEncoder().encode(type);
  const lengthBytes = new Uint8Array(4);
  writeUint32BE(lengthBytes, 0, data.length);
  const crcInput = concatByteArrays([typeBytes, data]);
  const crcBytes = new Uint8Array(4);
  writeUint32BE(crcBytes, 0, crc32(crcInput));
  return concatByteArrays([lengthBytes, typeBytes, data, crcBytes]);
}

function setPngResolutionDpi(bytes: Uint8Array, dpi: number) {
  if (
    bytes.length < PNG_SIGNATURE.length ||
    !PNG_SIGNATURE.every((value, index) => bytes[index] === value)
  ) {
    return bytes;
  }

  const pixelsPerMeter = Math.max(1, Math.round(dpi / 0.0254));
  const physData = new Uint8Array(9);
  writeUint32BE(physData, 0, pixelsPerMeter);
  writeUint32BE(physData, 4, pixelsPerMeter);
  physData[8] = 1;
  const physChunk = buildPngChunk("pHYs", physData);

  let offset = PNG_SIGNATURE.length;
  let insertOffset = -1;

  while (offset + 8 <= bytes.length) {
    const chunkLength = readUint32BE(bytes, offset);
    const chunkTypeOffset = offset + 4;
    const chunkDataOffset = offset + 8;
    const chunkTotalLength = 12 + chunkLength;
    if (chunkDataOffset + chunkLength + 4 > bytes.length) break;

    const chunkType = String.fromCharCode(
      bytes[chunkTypeOffset],
      bytes[chunkTypeOffset + 1],
      bytes[chunkTypeOffset + 2],
      bytes[chunkTypeOffset + 3]
    );

    if (chunkType === "IHDR") {
      insertOffset = offset + chunkTotalLength;
    } else if (chunkType === "pHYs") {
      return concatByteArrays([
        bytes.slice(0, offset),
        physChunk,
        bytes.slice(offset + chunkTotalLength),
      ]);
    }

    offset += chunkTotalLength;
    if (chunkType === "IEND") break;
  }

  if (insertOffset < 0) return bytes;
  return concatByteArrays([
    bytes.slice(0, insertOffset),
    physChunk,
    bytes.slice(insertOffset),
  ]);
}

function applyExportResolutionMetadata(bytes: Uint8Array, mime: string) {
  if (mime === "image/png") {
    return setPngResolutionDpi(bytes, EXPORT_DPI);
  }
  return bytes;
}

async function dataUrlToBlobWithProgress(
  dataUrl: string,
  onProgress?: (p: number) => void,
  startPct = 96,
  endPct = 100
): Promise<Blob> {
  const comma = dataUrl.indexOf(",");
  const header = dataUrl.slice(0, comma);
  const b64 = dataUrl.slice(comma + 1);
  const mimeMatch = /data:([^;]+);base64/.exec(header);
  const mime = mimeMatch ? mimeMatch[1] : "application/octet-stream";
  const total = b64.length;
  const sliceSize = 1024 * 1024; // 1MB base64 chunks
  const chunks: Uint8Array[] = [];

  for (let offset = 0; offset < total; offset += sliceSize) {
    const slice = b64.slice(offset, offset + sliceSize);
    const bin = atob(slice);
    const len = bin.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) bytes[i] = bin.charCodeAt(i);
    chunks.push(bytes);
    const pct = startPct + Math.round(((offset + slice.length) / total) * (endPct - startPct));
    onProgress?.(Math.min(endPct, pct));
    // Yield to keep UI responsive
    await new Promise((r) => setTimeout(r, 0));
  }

  const encodedBytes = concatByteArrays(chunks);
  const outputBytes = applyExportResolutionMetadata(encodedBytes, mime);
  const outputBuffer = new ArrayBuffer(outputBytes.byteLength);
  new Uint8Array(outputBuffer).set(outputBytes);
  return new Blob([outputBuffer], { type: mime });
}

function extractCssUrls(input: string): string[] {
  const urls: string[] = [];
  const re = /url\((['"]?)(.*?)\1\)/g;
  let m: RegExpExecArray | null;
  while ((m = re.exec(input))) {
    if (m[2]) urls.push(m[2]);
  }
  return urls;
}
const EXPORT_TRANSPARENT_PIXEL =
  "data:image/gif;base64,R0lGODlhAQABAIAAAAAAAP///ywAAAAAAQABAAACAUwAOw==";
const MOBILE_EXPORT_MAX_DIM = 8192;
const DESKTOP_JPG_EXPORT_MAX_DIM = 3200;
const DESKTOP_JPG_EXPORT_MAX_PIXELS = 9_000_000;

function clampDesktopJpgExportScale(
  requestedScale: number,
  width: number,
  height: number
) {
  const baseMaxDim = Math.max(width, height, 1);
  const safeByDim = DESKTOP_JPG_EXPORT_MAX_DIM / baseMaxDim;
  const safeByPixels = Math.sqrt(
    DESKTOP_JPG_EXPORT_MAX_PIXELS / Math.max(width * height, 1)
  );
  const safeScale = Math.max(
    1,
    Math.min(requestedScale, safeByDim, safeByPixels)
  );
  return Math.floor(safeScale * 100) / 100;
}

function splitCssListPreservingFunctions(input: string): string[] {
  const out: string[] = [];
  let buf = "";
  let depth = 0;
  for (let i = 0; i < input.length; i++) {
    const ch = input[i];
    if (ch === "(") depth++;
    if (ch === ")") depth = Math.max(0, depth - 1);
    if (ch === "," && depth === 0) {
      const part = buf.trim();
      if (part) out.push(part);
      buf = "";
      continue;
    }
    buf += ch;
  }
  const tail = buf.trim();
  if (tail) out.push(tail);
  return out;
}

function textShadowToDropShadowFilter(textShadow: string): string {
  if (!textShadow || textShadow === "none") return "";
  const parts = splitCssListPreservingFunctions(textShadow);
  const filters: string[] = [];
  const lengthRe = /(-?\d*\.?\d+px)\s+(-?\d*\.?\d+px)(?:\s+(\d*\.?\d+px))?/;

  for (const part of parts) {
    const m = part.match(lengthRe);
    if (!m) continue;
    const x = m[1];
    const y = m[2];
    const blur = m[3] || "0px";
    const color = part.replace(lengthRe, "").trim() || "rgba(0,0,0,0.55)";
    filters.push(`drop-shadow(${x} ${y} ${blur} ${color})`);
  }

  return filters.join(" ");
}

function applyTextShadowFallbackForExport(root: HTMLElement) {
  const swaps: Array<{
    el: HTMLElement;
    filter: string;
    textShadow: string;
  }> = [];
  const nodes = Array.from(root.querySelectorAll("*")).filter(
    (el) => !(el as HTMLElement).closest?.('[data-nonexport="true"]')
  ) as HTMLElement[];

  for (const el of nodes) {
    const computed = getComputedStyle(el);
    const ts = computed.textShadow;
    if (!ts || ts === "none") continue;
    const ds = textShadowToDropShadowFilter(ts);
    if (!ds) continue;

    swaps.push({
      el,
      filter: el.style.filter,
      textShadow: el.style.textShadow,
    });

    const baseFilter = el.style.filter && el.style.filter !== "none" ? `${el.style.filter} ` : "";
    el.style.textShadow = "none";
    el.style.filter = `${baseFilter}${ds}`.trim();
  }

  return () => {
    for (const s of swaps) {
      try { s.el.style.filter = s.filter; } catch {}
      try { s.el.style.textShadow = s.textShadow; } catch {}
    }
  };
}

async function waitForImageUrl(url?: string | null) {
  if (!url) return;
  try {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.src = url;
    if ((img as any).decode) {
      await (img as any).decode();
    } else {
      await new Promise<void>((resolve) => {
        img.onload = () => resolve();
        img.onerror = () => resolve();
      });
    }
  } catch {
    // ignore
  }
}

async function waitForBackgroundImages(root: HTMLElement) {
  const urls = new Set<string>();
  try {
    const nodes = Array.from(root.querySelectorAll('*')) as HTMLElement[];
    for (const el of nodes) {
      const bg = getComputedStyle(el).backgroundImage;
      if (!bg || bg === 'none') continue;
      if (bg.includes('gradient')) continue;
      extractCssUrls(bg).forEach((u) => urls.add(u));
    }
  } catch {
    // ignore
  }
  await Promise.all(Array.from(urls).map((u) => waitForImageUrl(u)));
}

function getScrollParent(el: HTMLElement): HTMLElement | null {
  let p: HTMLElement | null = el.parentElement;
  while (p) {
    const style = window.getComputedStyle(p);
    const overflowY = style.overflowY;
    if ((overflowY === "auto" || overflowY === "scroll") && p.scrollHeight > p.clientHeight) {
      return p;
    }
    p = p.parentElement;
  }
  return null;
}

function scrollToEl(el: HTMLElement, align: "center" | "start" = "center") {
  const parent = getScrollParent(el);
  const rect = el.getBoundingClientRect();
  if (!parent) {
    const top =
      align === "center"
        ? window.scrollY + rect.top + rect.height / 2 - window.innerHeight / 2
        : window.scrollY + rect.top - 12;
    window.scrollTo({ top, behavior: "smooth" });
    return;
  }
  const parentRect = parent.getBoundingClientRect();
  const top =
    align === "center"
      ? parent.scrollTop + (rect.top - parentRect.top) + rect.height / 2 - parent.clientHeight / 2
      : parent.scrollTop + (rect.top - parentRect.top) - 12;
  parent.scrollTo({ top, behavior: "smooth" });
}

async function waitForImages(root: HTMLElement) {
  const imgs = Array.from(root.querySelectorAll('img')).filter(
    (img) => !img.closest?.('[data-nonexport="true"]')
  ) as HTMLImageElement[];
  await Promise.all(
    imgs.map(async (img) => {
      try {
        if (img.complete && img.naturalWidth > 0) return;
        if ('decode' in img) {
          await (img as any).decode();
        } else {
          await new Promise<void>((resolve) => {
            (img as HTMLImageElement).onload = () => resolve();
            (img as HTMLImageElement).onerror = () => resolve();
          });
        }
      } catch {
        // ignore decode errors, proceed with export
      }
    })
  );
}

async function inlineImagesForExport(
  root: HTMLElement,
  opts?: { forceProxy?: boolean }
) {
  const imgs = Array.from(root.querySelectorAll('img')).filter(
    (img) => !img.closest?.('[data-nonexport="true"]')
  ) as HTMLImageElement[];
  const cache = new Map<string, string | null>();
  const swaps: Array<{
    el: HTMLImageElement;
    src: string;
    srcset: string | null;
    sizes: string | null;
  }> = [];
  const missing: string[] = [];

  for (const img of imgs) {
    const rawSrc = img.currentSrc || img.getAttribute('src') || '';
    if (!rawSrc) continue;
    if (rawSrc.startsWith('about:')) continue;

    const absSrc = rawSrc.startsWith('http') || rawSrc.startsWith('blob:') || rawSrc.startsWith('data:')
      ? rawSrc
      : new URL(rawSrc, window.location.href).toString();
    const isSameOrigin = (() => {
      try {
        return new URL(absSrc).origin === window.location.origin;
      } catch {
        return false;
      }
    })();
    if (!cache.has(absSrc)) {
      try {
        if (absSrc.startsWith('data:')) {
          cache.set(absSrc, absSrc);
        } else if (absSrc.startsWith('blob:')) {
          const blobRes = await fetch(absSrc, { cache: 'no-store' });
          if (!blobRes.ok) throw new Error('blob fetch failed');
          cache.set(absSrc, await blobToDataURL(await blobRes.blob()));
        } else {
          // In forced-proxy mode, still allow same-origin direct fetches.
          if (opts?.forceProxy && !isSameOrigin) {
            throw new Error('force proxy');
          }
          const res = await fetch(absSrc, {
            mode: 'cors',
            credentials: 'omit',
            cache: 'no-store',
          });
          if (!res.ok) throw new Error('fetch failed');
          const blob = await res.blob();
          cache.set(absSrc, await blobToDataURL(blob));
        }
      } catch {
        if (/^https?:/i.test(absSrc)) {
          // Proxy via same-origin to avoid CORS blocks (mobile-safe)
          try {
            const proxied = await fetch(`/api/image-proxy?url=${encodeURIComponent(absSrc)}`, {
              cache: "no-store",
            });
            if (!proxied.ok) throw new Error('proxy failed');
            const data = await proxied.json();
            if (data?.dataUrl) {
              cache.set(absSrc, data.dataUrl);
            } else {
              cache.set(absSrc, null);
            }
          } catch {
            cache.set(absSrc, null);
          }
        } else {
          cache.set(absSrc, null);
        }
      }
    }

    const inlinedSrc = cache.get(absSrc);
    if (!inlinedSrc) {
      missing.push(absSrc);
      swaps.push({
        el: img,
        src: img.getAttribute('src') || rawSrc,
        srcset: img.getAttribute('srcset'),
        sizes: img.getAttribute('sizes'),
      });
      img.setAttribute('src', EXPORT_TRANSPARENT_PIXEL);
      if (img.getAttribute('srcset')) img.removeAttribute('srcset');
      if (img.getAttribute('sizes')) img.removeAttribute('sizes');
      continue;
    }

    swaps.push({
      el: img,
      src: img.getAttribute('src') || rawSrc,
      srcset: img.getAttribute('srcset'),
      sizes: img.getAttribute('sizes'),
    });

    img.setAttribute('src', inlinedSrc);
    if (img.getAttribute('srcset')) img.removeAttribute('srcset');
    if (img.getAttribute('sizes')) img.removeAttribute('sizes');
  }

  const restore = () => {
    for (const swap of swaps) {
      try {
        swap.el.setAttribute('src', swap.src);
      } catch {}
      if (swap.srcset != null) {
        try { swap.el.setAttribute('srcset', swap.srcset); } catch {}
      } else {
        try { swap.el.removeAttribute('srcset'); } catch {}
      }
      if (swap.sizes != null) {
        try { swap.el.setAttribute('sizes', swap.sizes); } catch {}
      } else {
        try { swap.el.removeAttribute('sizes'); } catch {}
      }
    }
  };
  return { restore, missing };
}

async function inlineBackgroundImagesForExport(
  root: HTMLElement,
  opts?: { forceProxy?: boolean }
) {
  const nodes = Array.from(root.querySelectorAll('*')).filter(
    (el) => !el.closest?.('[data-nonexport="true"]')
  ) as HTMLElement[];
  const swaps: Array<{ el: HTMLElement; bg: string }> = [];
  const missing: string[] = [];

  for (const el of nodes) {
    const style = getComputedStyle(el);
    const bg = style.backgroundImage;
    if (!bg || bg === "none" || bg.includes("gradient")) continue;

    const urls = extractCssUrls(bg).filter(
      (u) => u && /^(https?:|blob:|data:image\/)/i.test(u)
    );
    if (!urls.length) continue;

    let nextBg = bg;
    for (const url of urls) {
      let dataUrl: string | null = null;
      try {
        if (/^data:image\//i.test(url)) {
          dataUrl = url;
        } else if (url.startsWith("blob:")) {
          const blobRes = await fetch(url, { cache: "no-store" });
          if (!blobRes.ok) throw new Error("blob fetch failed");
          dataUrl = await blobToDataURL(await blobRes.blob());
        } else {
          const isSameOrigin = (() => {
            try {
              return new URL(url).origin === window.location.origin;
            } catch {
              return false;
            }
          })();

          // In forced-proxy mode, still allow same-origin direct fetches.
          if (opts?.forceProxy && isSameOrigin) {
            const sameOriginRes = await fetch(url, { cache: "no-store", credentials: "omit" });
            if (!sameOriginRes.ok) throw new Error("fetch failed");
            const sameOriginBlob = await sameOriginRes.blob();
            dataUrl = await blobToDataURL(sameOriginBlob);
          } else {
            const res = await fetch(`/api/image-proxy?url=${encodeURIComponent(url)}`, {
              cache: "no-store",
            });
            if (res.ok) {
              const data = await res.json();
              if (data?.dataUrl) dataUrl = data.dataUrl;
            }
          }
        }
      } catch {}
      if (dataUrl) {
        // Replace only the matching URL token in the CSS string
        nextBg = nextBg.replace(url, dataUrl);
      } else {
        missing.push(url);
        nextBg = nextBg.replace(url, EXPORT_TRANSPARENT_PIXEL);
      }
    }

    if (nextBg !== bg) {
      swaps.push({ el, bg: el.style.backgroundImage });
      el.style.backgroundImage = nextBg;
    }
  }

  const restore = () => {
    for (const s of swaps) {
      try { s.el.style.backgroundImage = s.bg; } catch {}
    }
  };
  return { restore, missing };
}
// ===== EXPORT BEGIN (used by Export modal) =====
async function renderExportDataUrl(
  art: HTMLElement,
  format: 'png' | 'jpg',
  scale: number,
  onProgress?: (p: number) => void,
  forceProxy?: boolean
) {
  const exportRoot =
    (art.closest?.('[data-export-root="true"]') as HTMLElement) ||
    (document.getElementById('export-root') as HTMLElement) ||
    art;
  const wrapper = artWrapRef.current || exportRoot;
  const captureNode = art;
  const exportWidth = canvasSize.w;
  const exportHeight = canvasSize.h;
  let originalStyle: {
    transform: string;
    position: string;
    left: string;
    top: string;
    margin: string;
    width: string;
    height: string;
    transition: string;
    exportRootWidth: string;
    exportRootHeight: string;
    exportRootBorderRadius: string;
    exportRootOverflow: string;
    backgroundImage: string;
    backgroundSize: string;
    backgroundPosition: string;
    backgroundRepeat: string;
    artWidth: string;
    artHeight: string;
    artBorderRadius: string;
    artOverflow: string;
    artBoxShadow: string;
  } | null = null;
  let bgBlobUrl: string | null = null;
  let tempBgEl: HTMLDivElement | null = null;

  const isMobileExport =
    typeof navigator !== "undefined" &&
    /iPad|iPhone|iPod|Android/i.test(navigator.userAgent || "");
  const shouldInlineProxy = !!(isMobileExport || forceProxy);

  try {
    if (!art) throw new Error('Artboard not ready');

    setIsGenerating(true);
    setHideUiForExport(true);
    clearAllSelections();
    onProgress?.(8);

    (window as any).__HIDE_UI_EXPORT__ = true;
    await new Promise((r) => setTimeout(r, 150));
    await twoRaf();
    onProgress?.(18);

    originalStyle = {
      transform: wrapper.style.transform,
      position: wrapper.style.position,
      left: wrapper.style.left,
      top: wrapper.style.top,
      margin: wrapper.style.margin,
      width: wrapper.style.width,
      height: wrapper.style.height,
      transition: wrapper.style.transition,
      exportRootWidth: exportRoot.style.width,
      exportRootHeight: exportRoot.style.height,
      exportRootBorderRadius: exportRoot.style.borderRadius,
      exportRootOverflow: exportRoot.style.overflow,
      backgroundImage: exportRoot.style.backgroundImage,
      backgroundSize: exportRoot.style.backgroundSize,
      backgroundPosition: exportRoot.style.backgroundPosition,
      backgroundRepeat: exportRoot.style.backgroundRepeat,
      artWidth: art.style.width,
      artHeight: art.style.height,
      artBorderRadius: art.style.borderRadius,
      artOverflow: art.style.overflow,
      artBoxShadow: art.style.boxShadow,
    };

    wrapper.style.transform = "none";
    wrapper.style.position = "relative";
    wrapper.style.left = "0";
    wrapper.style.top = "0";
    wrapper.style.margin = "0";
    wrapper.style.width = `${exportWidth}px`;
    wrapper.style.height = `${exportHeight}px`;
    wrapper.style.transition = "none";
    exportRoot.style.width = `${exportWidth}px`;
    exportRoot.style.height = `${exportHeight}px`;
    exportRoot.style.borderRadius = "0px";
    exportRoot.style.overflow = "hidden";
    art.style.width = `${exportWidth}px`;
    art.style.height = `${exportHeight}px`;
    art.style.borderRadius = "0px";
    art.style.overflow = "hidden";
    art.style.boxShadow = "none";

    await new Promise((r) => setTimeout(r, 100));
    await twoRaf();
    onProgress?.(28);

    const families = [
      headlineFamily,
      head2Family,
      bodyFamily,
      detailsFamily,
      details2Family,
      subtagFamily,
      venueFamily,
    ].filter(Boolean);

    try {
      const uniq = Array.from(new Set(families));
      await Promise.all(
        uniq.flatMap((f) => [
          (document as any).fonts?.load?.(`400 16px "${f}"`),
          (document as any).fonts?.load?.(`700 16px "${f}"`),
        ])
      );
      await (document as any).fonts?.ready;
    } catch {}
    try {
      await forceFontRender(families);
      await waitForFamilies(families);
      await (document as any).fonts?.ready;
    } catch {}
    onProgress?.(40);

    // Force a baked background layer to avoid missing CSS bg on mobile export
    let bgSrcForExport: string | null = null;
    try {
      const snapSize = Math.min(
        MOBILE_EXPORT_MAX_DIM,
        Math.max(canvasSize.w, canvasSize.h) * Math.max(1, scale)
      );
      const bgSnap = await (artRef.current as any)?.exportBackgroundDataUrl?.({ size: snapSize });
      if (bgSnap) bgSrcForExport = bgSnap;
    } catch {
      // ignore if snapshot fails
    }
    // Fallback: enforce a same-origin background to avoid CORS drops
    try {
      if (!bgSrcForExport) {
        if (bgUploadUrl) {
          bgSrcForExport = bgUploadUrl;
        } else if (bgUrl && bgUrl.startsWith("http")) {
          const res = await fetch(bgUrl);
          const blob = await res.blob();
          bgBlobUrl = URL.createObjectURL(blob);
          bgSrcForExport = bgBlobUrl;
        } else if (bgUrl) {
          bgSrcForExport = bgUrl;
        }
      }
    } catch {
      // ignore fallback failures
    }
    if (bgSrcForExport) {
      exportRoot.style.backgroundImage = "none";
      tempBgEl = document.createElement("div");
      tempBgEl.setAttribute("data-export-temp-bg", "true");
      Object.assign(tempBgEl.style, {
        position: "absolute",
        inset: "0px",
        zIndex: "0",
        overflow: "hidden",
        pointerEvents: "none",
      });
      const img = document.createElement("img");
      img.src = bgSrcForExport;
      img.style.width = "100%";
      img.style.height = "100%";
      img.style.objectFit = "cover";
      img.style.display = "block";
      tempBgEl.appendChild(img);
      captureNode.insertBefore(tempBgEl, captureNode.firstChild);
      await waitForImageUrl(bgSrcForExport);
    }
    onProgress?.(55);

    const exportStyle = getComputedStyle(captureNode);
    const forcedStyle: any = {
      filter: exportStyle.filter,
      webkitFilter: exportStyle.filter,
      backdropFilter: (exportStyle as any).backdropFilter,
      WebkitBackdropFilter:
        (exportStyle as any).backdropFilter ||
        (exportStyle as any).WebkitBackdropFilter,
      transform: "none",
      left: "0px",
      top: "0px",
      margin: "0",
      position: "relative",
      borderRadius: "0px",
      boxShadow: "none",
      overflow: "hidden",
      width: `${exportWidth}px`,
      height: `${exportHeight}px`,
      maxWidth: "none",
      maxHeight: "none",
    };
    const captureOptions = {
      cacheBust: true,
      imagePlaceholder: EXPORT_TRANSPARENT_PIXEL,
      backgroundColor: '#000',
      pixelRatio: scale,
      width: exportWidth,
      height: exportHeight,
      canvasWidth: exportWidth,
      canvasHeight: exportHeight,
      skipAutoScale: true,
      style: forcedStyle,
      filter: (node: HTMLElement) => {
        const el = node as HTMLElement;
        if (!el) return true;
        const skip =
          el.dataset?.nonexport === 'true' ||
          el.classList?.contains('debug-grid') ||
          el.classList?.contains('bounding-box') ||
          el.classList?.contains('text-bounding') ||
          el.classList?.contains('text-outline') ||
          el.classList?.contains('highlight-box') ||
          el.classList?.contains('drag-handle') ||
          el.classList?.contains('resize-handle') ||
          el.classList?.contains('portrait-handle') ||
          el.classList?.contains('portrait-bounding') ||
          el.classList?.contains('portrait-outline') ||
          el.classList?.contains('portrait-border') ||
          el.classList?.contains('portrait-slot') ||
          el.classList?.contains('overlay-grid') ||
          el.tagName === 'BUTTON' ||
          el.tagName === 'INPUT' ||
          el.tagName === 'TEXTAREA';
        return !skip;
      },
    };

    const dataUrl = await withExternalStylesDisabled(async () => {
      let restoreExportFonts: null | (() => void) = null;
      let restoreTextShadowFallback: null | (() => void) = null;
      let restoreInlineImages: null | (() => void) = null;
      let restoreInlineBg: null | (() => void) = null;
      let missingInline: string[] = [];
      let missingBgInline: string[] = [];
      try {
        await forceFontRender(families);
        const injectedFonts = await injectGoogleFontsForExport(captureNode, families);
        restoreExportFonts = injectedFonts.restore;
        if (isMobileExport) {
          restoreTextShadowFallback = applyTextShadowFallbackForExport(captureNode);
        }
        await waitForImageUrl(bgUploadUrl || bgUrl);
        await waitForImageUrl(logoUrl);
        if (shouldInlineProxy) {
          const inlineImgs = await inlineImagesForExport(captureNode, { forceProxy: true });
          restoreInlineImages = inlineImgs.restore;
          missingInline = inlineImgs.missing;
          const inlineBg = await inlineBackgroundImagesForExport(captureNode, { forceProxy: true });
          restoreInlineBg = inlineBg.restore;
          missingBgInline = inlineBg.missing;
          const missingAll = [...missingInline, ...missingBgInline];
        }
        await waitForImages(captureNode);
        await waitForBackgroundImages(captureNode);
        onProgress?.(70);

        const capture = async () => {
          if (format === 'jpg') {
            return await htmlToImage.toJpeg(captureNode, {
              ...captureOptions,
              quality: 0.95,
            });
          }

          return await htmlToImage.toPng(captureNode, captureOptions);
        };

        const needsWarmup = format !== 'jpg' && !!(bgUploadUrl || bgUrl || logoUrl);
        if (!needsWarmup) return await capture();

        await capture(); // warm-up pass
        onProgress?.(85);
        await new Promise((r) => setTimeout(r, 200));
        const out = await capture(); // final pass
        onProgress?.(96);
        return out;
      } finally {
        if (restoreExportFonts) restoreExportFonts();
        if (restoreTextShadowFallback) restoreTextShadowFallback();
        if (restoreInlineImages) restoreInlineImages();
        if (restoreInlineBg) restoreInlineBg();
      }
    });

    (window as any).__HIDE_UI_EXPORT__ = false;
    setHideUiForExport(false);

    wrapper.style.transform = originalStyle.transform;
    wrapper.style.position = originalStyle.position;
    wrapper.style.left = originalStyle.left;
    wrapper.style.top = originalStyle.top;
    wrapper.style.margin = originalStyle.margin;
    wrapper.style.width = originalStyle.width;
    wrapper.style.height = originalStyle.height;
    wrapper.style.transition = originalStyle.transition;
    exportRoot.style.width = originalStyle.exportRootWidth;
    exportRoot.style.height = originalStyle.exportRootHeight;
    exportRoot.style.borderRadius = originalStyle.exportRootBorderRadius;
    exportRoot.style.overflow = originalStyle.exportRootOverflow;
    exportRoot.style.backgroundImage = originalStyle.backgroundImage;
    exportRoot.style.backgroundSize = originalStyle.backgroundSize;
    exportRoot.style.backgroundPosition = originalStyle.backgroundPosition;
    exportRoot.style.backgroundRepeat = originalStyle.backgroundRepeat;
    art.style.width = originalStyle.artWidth;
    art.style.height = originalStyle.artHeight;
    art.style.borderRadius = originalStyle.artBorderRadius;
    art.style.overflow = originalStyle.artOverflow;
    art.style.boxShadow = originalStyle.artBoxShadow;
    if (tempBgEl && tempBgEl.parentNode) {
      try { tempBgEl.parentNode.removeChild(tempBgEl); } catch {}
      tempBgEl = null;
    }
    if (bgBlobUrl) {
      try { URL.revokeObjectURL(bgBlobUrl); } catch {}
      bgBlobUrl = null;
    }
    onProgress?.(100);

    return dataUrl;
  } catch (err) {
    (window as any).__HIDE_UI_EXPORT__ = false;
    throw err;
  } finally {
    setIsGenerating(false);
    setHideUiForExport(false);
    if (originalStyle) {
      wrapper.style.transform = originalStyle.transform;
      wrapper.style.position = originalStyle.position;
      wrapper.style.left = originalStyle.left;
      wrapper.style.top = originalStyle.top;
      wrapper.style.margin = originalStyle.margin;
      wrapper.style.width = originalStyle.width;
      wrapper.style.height = originalStyle.height;
      wrapper.style.transition = originalStyle.transition;
      exportRoot.style.width = originalStyle.exportRootWidth;
      exportRoot.style.height = originalStyle.exportRootHeight;
      exportRoot.style.borderRadius = originalStyle.exportRootBorderRadius;
      exportRoot.style.overflow = originalStyle.exportRootOverflow;
      exportRoot.style.backgroundImage = originalStyle.backgroundImage;
      exportRoot.style.backgroundSize = originalStyle.backgroundSize;
      exportRoot.style.backgroundPosition = originalStyle.backgroundPosition;
      exportRoot.style.backgroundRepeat = originalStyle.backgroundRepeat;
      art.style.width = originalStyle.artWidth;
      art.style.height = originalStyle.artHeight;
      art.style.borderRadius = originalStyle.artBorderRadius;
      art.style.overflow = originalStyle.artOverflow;
      art.style.boxShadow = originalStyle.artBoxShadow;
      if (tempBgEl && tempBgEl.parentNode) {
        try { tempBgEl.parentNode.removeChild(tempBgEl); } catch {}
        tempBgEl = null;
      }
      if (bgBlobUrl) {
        try { URL.revokeObjectURL(bgBlobUrl); } catch {}
        bgBlobUrl = null;
      }
    }
  }
}
