const formatStatusTimestamp = React.useCallback((raw: string | number | null | undefined) => {
  if (raw == null) return null;
  const normalized =
    typeof raw === "number"
      ? raw
      : /^\d+$/.test(String(raw).trim())
      ? Number(raw)
      : raw;
  const parsed = new Date(normalized);
  if (Number.isNaN(parsed.getTime())) return null;
  return new Intl.DateTimeFormat("en-US", {
    month: "short",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit",
  }).format(parsed);
}, []);
const projectFileStatusLabel = React.useMemo(() => {
  return formatStatusTimestamp(projectFileStatus?.at);
}, [formatStatusTimestamp, projectFileStatus?.at]);
const floatingAssetRef = React.useRef<HTMLDivElement | null>(null);
const floatingTextRef = React.useRef<HTMLDivElement | null>(null);
const floatingBgRef = React.useRef<HTMLDivElement | null>(null);
const floatingLightingRef = React.useRef<HTMLDivElement | null>(null);
const floatFocusLockRef = React.useRef(false);
const floatRecentInteractionAtRef = React.useRef(0);

function markFloatInteraction() {
  floatRecentInteractionAtRef.current = Date.now();
}

function floatRecentlyInteracted() {
  return Date.now() - floatRecentInteractionAtRef.current < 900;
}

function eventWithinAnyFloat(ev?: Event) {
  const anyEv = ev as any;
  const t = anyEv?.target as HTMLElement | null;
  if (t?.closest?.('[data-floating-controls]')) return true;
  if (t?.closest?.('[data-mobile-float-lock="true"]')) return true;
  const path = (anyEv?.composedPath?.() || []) as any[];
  if (path?.length) {
    for (const node of path) {
      if (!node) continue;
      if ((node as any)?.dataset?.floatingControls) return true;
      if ((node as any)?.dataset?.mobileFloatLock === "true") return true;
      if (floatingTextRef.current && node === floatingTextRef.current) return true;
      if (floatingAssetRef.current && node === floatingAssetRef.current) return true;
      if (floatingBgRef.current && node === floatingBgRef.current) return true;
      if (floatingLightingRef.current && node === floatingLightingRef.current) return true;
    }
  }
  return false;
}

function activeElementWithinAnyFloat() {
  const active = document.activeElement as HTMLElement | null;
  if (!active) return false;
  if (active.closest?.('[data-floating-controls]')) return true;
  if (active.closest?.('[data-mobile-float-lock="true"]')) return true;
  return (
    (floatingTextRef.current && floatingTextRef.current.contains(active)) ||
    (floatingAssetRef.current && floatingAssetRef.current.contains(active)) ||
    (floatingBgRef.current && floatingBgRef.current.contains(active)) ||
    (floatingLightingRef.current && floatingLightingRef.current.contains(active))
  );
}

