React.useEffect(() => {
  const onFocusIn = (ev: FocusEvent) => {
    const t = ev.target as HTMLElement | null;
    if (!t) return;
    if (t.closest?.('[data-floating-controls]')) {
      floatFocusLockRef.current = true;
      markFloatInteraction();
    }
  };
  const onFocusOut = () => {
    setTimeout(() => {
      const active = document.activeElement as HTMLElement | null;
      if (!active || !active.closest?.('[data-floating-controls]')) {
        floatFocusLockRef.current = false;
      }
    }, 0);
  };
  document.addEventListener("focusin", onFocusIn, true);
  document.addEventListener("focusout", onFocusOut, true);
  return () => {
    document.removeEventListener("focusin", onFocusIn, true);
    document.removeEventListener("focusout", onFocusOut, true);
  };
}, []);

React.useEffect(() => {
  if (!projectHelpOpen && !workflowHelpOpen) return;
  const prev = document.body.style.overflow;
  document.body.style.overflow = "hidden";
  const onKey = (e: KeyboardEvent) => {
    if (e.key === "Escape") {
      setProjectHelpOpen(false);
      setWorkflowHelpOpen(false);
    }
  };
  window.addEventListener("keydown", onKey);
  return () => {
    document.body.style.overflow = prev;
    window.removeEventListener("keydown", onKey);
  };
}, [projectHelpOpen, workflowHelpOpen]);

