const ASSET_LAYER_STEP = 8;
const ASSET_LAYER_MIN = -120;
const ASSET_LAYER_MAX = 160;
const nudgeAssetLayerOffset = (
  current: number | undefined,
  direction: "up" | "down"
) => {
  const delta = direction === "up" ? ASSET_LAYER_STEP : -ASSET_LAYER_STEP;
  return Math.max(ASSET_LAYER_MIN, Math.min(ASSET_LAYER_MAX, (current ?? 0) + delta));
};
const nudgeEmojiLayer = React.useCallback(
  (id: string, direction: "up" | "down") => {
    const st = useFlyerState.getState();
    const bucket = Array.isArray(st.emojis?.[format]) ? st.emojis[format] : [];
    const cur = bucket.find((e: any) => e?.id === id);
    if (!cur) return;
    st.updateEmoji(format, id, {
      layerOffset: nudgeAssetLayerOffset((cur as any).layerOffset, direction),
    });
    st.setSelectedEmojiId(id);
    st.setSelectedPanel("icons");
    st.setMoveTarget("icon");
  },
  [format]
);
const nudgePortraitLayer = React.useCallback(
  (id: string, direction: "up" | "down") => {
    const st = useFlyerState.getState();
    const bucket = Array.isArray(st.portraits?.[format]) ? st.portraits[format] : [];
    const cur = bucket.find((p: any) => p?.id === id);
    if (!cur) return;
    st.updatePortrait(format, id, {
      layerOffset: nudgeAssetLayerOffset((cur as any).layerOffset, direction),
    });

    const isLogo = String(cur.id || "").startsWith("logo_") || !!(cur as any).isLogo;
    const isLibraryAsset = !!(cur as any).isFlare || !!(cur as any).isSticker;
    const isExtracted = !!(cur as any).isExtracted;
    st.setSelectedPortraitId(id);
    if (isLibraryAsset) {
      st.setSelectedPanel("icons");
      st.setMoveTarget("icon");
    } else if (isLogo) {
      st.setSelectedPanel("logo");
      st.setMoveTarget("logo");
    } else if (isExtracted) {
      st.setSelectedPanel("extract_subject");
      st.setMoveTarget("portrait");
    } else {
      st.setSelectedPanel("portrait");
      st.setMoveTarget("portrait");
    }
  },
  [format]
);

const activeAssetControls = React.useMemo(() => {
  if (selectedEmojiId) {
    const list = Array.isArray(emojis) ? emojis : emojis?.[format] || [];
    const sel = list.find((e: any) => e.id === selectedEmojiId);
    if (!sel) return null;
    return {
      label: "Emoji",
      idLabel: `${sel.id}`,
      showPosition: false,
      posX: sel.x ?? 0,
      posY: sel.y ?? 0,
      scale: sel.scale ?? 1,
      opacity: sel.opacity ?? 1,
      rotation: sel.rotation ?? 0,
      locked: !!sel.locked,
      tint: typeof sel.tint === "number" ? sel.tint : 0,
      onScale: (v: number) =>
        useFlyerState.getState().updateEmoji(format, sel.id, { scale: v }),
      onOpacity: (v: number) =>
        useFlyerState.getState().updateEmoji(format, sel.id, { opacity: v }),
      onRotate: (v: number) =>
        useFlyerState.getState().updateEmoji(format, sel.id, { rotation: v }),
      onTint: (v: number) =>
        useFlyerState.getState().updateEmoji(format, sel.id, { tint: v }),
      onPosX: (v: number) =>
        useFlyerState.getState().updateEmoji(format, sel.id, { x: clamp100(v) }),
      onPosY: (v: number) =>
        useFlyerState.getState().updateEmoji(format, sel.id, { y: clamp100(v) }),
      onToggleLock: () =>
        useFlyerState.getState().updateEmoji(format, sel.id, {
          locked: !sel.locked,
        }),
      onLayerUp: () => nudgeEmojiLayer(sel.id, "up"),
      onLayerDown: () => nudgeEmojiLayer(sel.id, "down"),
      onDelete: () => {
        useFlyerState.getState().removeEmoji(format, sel.id);
        setSelectedEmojiId(null);
      },
    };
  }

  if (selectedPortraitId) {
    const list = portraits?.[format] || [];
    const sel = list.find((p: any) => p.id === selectedPortraitId);
    if (!sel) return null;
    const isBrandFace = !!(sel as any).isBrandFace;
    const isLogo = String(sel.id || "").startsWith("logo_") || !!(sel as any).isLogo;
    const isExtracted = !!(sel as any).isExtracted;
    const isAsset = sel.isFlare || sel.isSticker || isLogo || isBrandFace;
    const isSeparator = !!(sel as any).isSeparator;
    const isShapeGraphic = !!(sel as any).isShapeGraphic;
    const hasIconColor =
      (!!(sel as any).isSticker && typeof (sel as any).svgTemplate === "string") || isSeparator;
    const assetName = resolveCanvasAssetName(sel) || (isLogo ? "3D Text" : null);
    const assetLabel = isBrandFace
      ? "Main Face"
      : assetName || (sel.isFlare ? "Flare" : sel.isSticker ? "Graphic" : "3D Text");

    if (isExtracted) {
      return {
        label: "Cutout",
        idLabel: `${sel.id}`,
        showPosition: false,
        scale: sel.scale ?? 1,
        showScale: true,
        scaleLabel: "Scale",
        scaleMin: 0.01,
        scaleMax: 5,
        scaleStep: 0.01,
        opacity: sel.opacity ?? 1,
        showOpacity: false,
        tint: typeof (sel as any).tint === "number" ? (sel as any).tint : 0,
        rotateFullWidth: true,
        shadowBlur: Number((sel as any).shadowBlur ?? 0),
        shadowStrength: Number((sel as any).shadowAlpha ?? 0.48),
        locked: !!sel.locked,
        rotation: sel.rotation ?? 0,
        onScale: (v: number) =>
          useFlyerState.getState().updatePortrait(format, sel.id, { scale: v }),
        onTint: (v: number) =>
          useFlyerState.getState().updatePortrait(format, sel.id, {
            tint: v,
            tintMode: "colorize",
          }),
        onShadowBlur: (v: number) =>
          useFlyerState.getState().updatePortrait(format, sel.id, { shadowBlur: v }),
        onShadowStrength: (v: number) =>
          useFlyerState.getState().updatePortrait(format, sel.id, { shadowAlpha: v }),
        onRotate: (v: number) =>
          useFlyerState.getState().updatePortrait(format, sel.id, { rotation: v }),
        onToggleLock: () =>
          useFlyerState.getState().updatePortrait(format, sel.id, {
            locked: !sel.locked,
          }),
        onLayerUp: () => nudgePortraitLayer(sel.id, "up"),
        onLayerDown: () => nudgePortraitLayer(sel.id, "down"),
        deleteLabel: "Delete Cutout",
        onDelete: () => {
          removePortrait(format, sel.id);
          useFlyerState.getState().setSelectedPortraitId(null);
        },
      };
    }

    if (isAsset) {
      if (isBrandFace) {
        return {
          label: "Main Face",
          idLabel: `${sel.id}`,
          isMainFace: true,
          scale: sel.scale ?? 1,
          opacity: sel.opacity ?? 1,
          locked: !!sel.locked,
          showOpacity: true,
          onScale: (v: number) =>
            useFlyerState.getState().updatePortrait(format, sel.id, { scale: v }),
          onOpacity: (v: number) =>
            useFlyerState.getState().updatePortrait(format, sel.id, { opacity: v }),
          onToggleLock: () =>
            useFlyerState.getState().updatePortrait(format, sel.id, {
              locked: !sel.locked,
            }),
          onLayerUp: () => nudgePortraitLayer(sel.id, "up"),
          onLayerDown: () => nudgePortraitLayer(sel.id, "down"),
          onDelete: () => {
            removePortrait(format, sel.id);
            useFlyerState.getState().setSelectedPortraitId(null);
          },
          onContinueToLighting: continueMainFaceToLighting,
        };
      }
      return {
        label: formatUiLabelCaps(assetLabel),
        idLabel: `${sel.id}`,
        showPosition: !(sel.isFlare || sel.isSticker || isLogo),
        posX: sel.x ?? 0,
        posY: sel.y ?? 0,
        scale: sel.scale ?? 1,
        showScale: true,
        scaleLabel: "Scale",
        scaleMin: 0.01,
        scaleMax: isShapeGraphic ? 6 : 5,
        scaleStep: 0.01,
        opacity: sel.opacity ?? 1,
        locked: !!sel.locked,
        showColor: hasIconColor,
        colorValue: (sel as any).iconColor || "#ffffff",
        shapeGradient: isShapeGraphic ? (sel as any).shapeGradient !== false : undefined,
        rotation: sel.rotation ?? 0,
        shadowBlur: isLogo ? Number((sel as any).shadowBlur ?? 0) : undefined,
        shadowStrength: isLogo ? Number((sel as any).shadowAlpha ?? 0.48) : undefined,
        separatorLength: isSeparator
          ? Number((sel as any).separatorWidth ?? 180)
          : isShapeGraphic
          ? Number((sel as any).shapeLength ?? 160)
          : undefined,
        shapeSkew: isShapeGraphic ? Number((sel as any).shapeSkew ?? 0) : undefined,
        lengthLabel: "Length",
        lengthMin: isShapeGraphic ? 48 : 128,
        lengthMax: isShapeGraphic ? 12000 : 720,
        lengthStep: isShapeGraphic ? 24 : 4,
        separatorOffset: isSeparator ? Number((sel as any).separatorOffset ?? 0) : undefined,
        // Main Face should stay clean; keep tint off for this asset type.
        tint:
          isBrandFace || isShapeGraphic
            ? undefined
            : typeof (sel as any).tint === "number"
            ? (sel as any).tint
            : 0,
        onColor: (value: string) => {
          const gradientEnabled = (sel as any).shapeGradient !== false;
          const nextUrl = isSeparator
            ? buildSeparatorSvgDataUrl(
                String((sel as any).separatorKind || ""),
                value,
                Number((sel as any).separatorWidth ?? 180),
                Number((sel as any).separatorOffset ?? 0)
              )
            : isShapeGraphic
            ? (() => {
                const kind = String((sel as any).shapeKind || "");
                const shapeItem = SHAPE_GRAPHICS.find((item) => item.id === kind);
                if (!shapeItem) return String(sel.url || "");
                return buildShapeSvgDataUrl(kind, value, gradientEnabled);
              })()
            : (() => {
                const template = String((sel as any).svgTemplate || "");
                const nextSvg = template.replace("{{COLOR}}", value);
                const svgBase64 = btoa(unescape(encodeURIComponent(nextSvg)));
                return `data:image/svg+xml;base64,${svgBase64}`;
              })();
          useFlyerState.getState().updatePortrait(format, sel.id, {
            url: nextUrl,
            iconColor: value,
          });
        },
        onToggleShapeGradient: isShapeGraphic
          ? () => {
              const nextGradient = (sel as any).shapeGradient === false;
              useFlyerState.getState().updatePortrait(format, sel.id, {
                shapeGradient: nextGradient,
                url: buildShapeSvgDataUrl(
                  String((sel as any).shapeKind || ""),
                  String((sel as any).iconColor || "#ffffff"),
                  nextGradient
                ),
                svgTemplate: buildShapeSvgMarkup(
                  String((sel as any).shapeKind || ""),
                  "{{COLOR}}",
                  nextGradient
                ),
              });
            }
          : undefined,
        onSeparatorLength: isSeparator
          ? (v: number) =>
              useFlyerState.getState().updatePortrait(format, sel.id, {
                separatorWidth: v,
                url: buildSeparatorSvgDataUrl(
                  String((sel as any).separatorKind || ""),
                  String((sel as any).iconColor || "#ffffff"),
                  v,
                  Number((sel as any).separatorOffset ?? 0)
                ),
              })
          : undefined,
        onSeparatorOffset: isSeparator
          ? (v: number) =>
              useFlyerState.getState().updatePortrait(format, sel.id, {
                separatorOffset: v,
                url: buildSeparatorSvgDataUrl(
                  String((sel as any).separatorKind || ""),
                  String((sel as any).iconColor || "#ffffff"),
                  Number((sel as any).separatorWidth ?? 180),
                  v
                ),
              })
          : isShapeGraphic
          ? (v: number) =>
              useFlyerState.getState().updatePortrait(format, sel.id, {
                shapeLength: v,
              })
          : undefined,
        onShapeSkew: isShapeGraphic
          ? (v: number) =>
              useFlyerState.getState().updatePortrait(format, sel.id, {
                shapeSkew: v,
              })
          : undefined,
        showLabel: isLogo ? undefined : !!(sel as any).showLabel,
        labelValue: isLogo ? undefined : String((sel as any).label ?? ""),
        onLabel: isLogo
          ? undefined
          : (v: string) =>
              useFlyerState.getState().updatePortrait(format, sel.id, { label: v }),
        labelSize: isLogo
          ? undefined
          : Number.isFinite((sel as any).labelSize)
          ? Number((sel as any).labelSize)
          : 9,
        onLabelSize: isLogo
          ? undefined
          : (v: number) =>
              useFlyerState.getState().updatePortrait(format, sel.id, { labelSize: v }),
        labelOffsetY: isLogo ? undefined : Number((sel as any).labelOffsetY ?? 0),
        onLabelOffsetY: isLogo
          ? undefined
          : (v: number) =>
              useFlyerState.getState().updatePortrait(format, sel.id, { labelOffsetY: v }),
        onToggleLabel: isLogo
          ? undefined
          : () =>
              useFlyerState.getState().updatePortrait(format, sel.id, {
                showLabel: !(sel as any).showLabel,
              }),
        labelBg: isLogo ? undefined : (sel as any).labelBg ?? true,
        onToggleLabelBg: isLogo
          ? undefined
          : () =>
              useFlyerState.getState().updatePortrait(format, sel.id, {
                labelBg: !((sel as any).labelBg ?? true),
              }),
        onScale: (v: number) =>
          useFlyerState.getState().updatePortrait(format, sel.id, { scale: v }),
        onOpacity: (v: number) =>
          useFlyerState.getState().updatePortrait(format, sel.id, { opacity: v }),
        onTint: isShapeGraphic
          ? undefined
          : (v: number) =>
              useFlyerState.getState().updatePortrait(format, sel.id, { tint: v }),
        onPosX: (v: number) =>
          useFlyerState.getState().updatePortrait(format, sel.id, { x: clamp100(v) }),
        onPosY: (v: number) =>
          useFlyerState.getState().updatePortrait(format, sel.id, { y: clamp100(v) }),
        onRotate: (v: number) =>
          useFlyerState.getState().updatePortrait(format, sel.id, { rotation: v }),
        onShadowBlur: isLogo
          ? (v: number) =>
              useFlyerState.getState().updatePortrait(format, sel.id, { shadowBlur: v })
          : undefined,
        onShadowStrength: isLogo
          ? (v: number) =>
              useFlyerState.getState().updatePortrait(format, sel.id, { shadowAlpha: v })
          : undefined,
        onToggleLock: () =>
          useFlyerState.getState().updatePortrait(format, sel.id, {
            locked: !sel.locked,
          }),
        onLayerUp: () => nudgePortraitLayer(sel.id, "up"),
        onLayerDown: () => nudgePortraitLayer(sel.id, "down"),
        deleteLabel: isBrandFace ? "Remove Main Face" : `Delete ${assetLabel}`,
        onDelete: () => {
          removePortrait(format, sel.id);
          useFlyerState.getState().setSelectedPortraitId(null);
        },
      };
    }

      return {
        label: "Portrait",
        idLabel: `${sel.id}`,
        posX: sel.x ?? 0,
        posY: sel.y ?? 0,
        scale: sel.scale ?? 1,
        opacity: sel.opacity ?? 1,
        locked: !!sel.locked,
        showOpacity: false,
      onScale: (v: number) =>
        useFlyerState.getState().updatePortrait(format, sel.id, { scale: v }),
      onToggleLock: () =>
        useFlyerState.getState().updatePortrait(format, sel.id, {
          locked: !sel.locked,
        }),
      onLayerUp: () => nudgePortraitLayer(sel.id, "up"),
      onLayerDown: () => nudgePortraitLayer(sel.id, "down"),
      onDelete: () => {
        removePortrait(format, sel.id);
        useFlyerState.getState().setSelectedPortraitId(null);
      },
    };
  }

  return null;
}, [
  selectedEmojiId,
  selectedPortraitId,
  emojis,
  portraits,
  format,
  removePortrait,
  nudgeEmojiLayer,
  nudgePortraitLayer,
  isLocked,
  onToggleLock,
]);

const headlineTextStyleTabsVisible = activeTextTarget === "headline";
const showMobileTextFloatBasics =
  !headlineTextStyleTabsVisible || mobileTextFloatTab === "text";
const showMobileHeadlineStyleControls =
  headlineTextStyleTabsVisible && mobileTextFloatTab === "style";
const showMobileHeadline3dControls =
  showMobileHeadlineStyleControls && mobileHeadlineStyleFocus === "3d";
const showMobileHeadlineGradientControls =
  showMobileHeadlineStyleControls && mobileHeadlineStyleFocus === "gradient";
const showMobileHeadlineEchoControls =
  showMobileHeadlineStyleControls && mobileHeadlineStyleFocus === "echo";
const activeMobileTextFloatPanelStyle = headlineTextStyleTabsVisible
  ? mobileHeadlineFloatPanelStyle
  : mobileFloatPanelStyle;
const hasAssetControls = !!activeAssetControls;

React.useEffect(() => {
  if (!floatingEditorVisible) return;
  setMobileTextFloatTab("text");
  setMobileHeadlineStyleFocus(null);
}, [activeTextTarget, floatingEditorVisible]);

const activeBgControls = React.useMemo(() => {
  if (selectedPanel !== "background" && moveTarget !== "background") return null;
  return {
    label: "Background",
    scale: bgScale,
    blur: bgBlur,
    hue,
    vignette: vignetteStrength,
    locked: bgLocked,
    onToggleLock: () => setBgLocked((v) => !v),
    onScale: (v: number) => setBgScale(v),
    onBlur: (v: number) => setBgBlur(v),
    onHue: (v: number) => setHue(v),
    onVignette: (v: number) => {
      setVignetteStrength(v);
      setVignette(v > 0.0001);
    },
  };
}, [selectedPanel, moveTarget, bgScale, bgBlur, hue, vignetteStrength, bgLocked]);

const recordMove = React.useCallback(
  (move: {
    kind:
      | "icon"
      | "emoji"
      | "portrait"
      | "headline"
      | "headline2"
      | "details"
      | "details2"
      | "venue"
      | "subtag"
      | "logo"
      | "background";
    id: string;
    x: number;
    y: number;
  }) => {
    setLastMoveStack((prev) => {
      const next = [...prev, move];
      return next.length > 3 ? next.slice(-3) : next;
    });
  },
  []
);

const undoAssetPosition = React.useCallback(() => {
  if (!lastMoveStack.length) return;
  const lastMovePos = lastMoveStack[lastMoveStack.length - 1];
  switch (lastMovePos.kind) {
    case "icon":
      updateIcon(lastMovePos.id, { x: lastMovePos.x, y: lastMovePos.y });
      break;
    case "emoji":
      updateEmoji(format, lastMovePos.id, {
        x: lastMovePos.x,
        y: lastMovePos.y,
      });
      break;
    case "portrait":
      updatePortrait(format, lastMovePos.id, {
        x: lastMovePos.x,
        y: lastMovePos.y,
      });
      break;
    case "headline":
      setHeadX(lastMovePos.x);
      setHeadY(lastMovePos.y);
      break;
    case "headline2":
      setHead2X(lastMovePos.x);
      setHead2Y(lastMovePos.y);
      break;
    case "details":
      setDetailsX(lastMovePos.x);
      setDetailsY(lastMovePos.y);
      break;
    case "details2":
      setDetails2X(lastMovePos.x);
      setDetails2Y(lastMovePos.y);
      break;
    case "venue":
      setVenueX(lastMovePos.x);
      setVenueY(lastMovePos.y);
      break;
    case "subtag":
      setSubtagX(lastMovePos.x);
      setSubtagY(lastMovePos.y);
      break;
    case "logo":
      setLogoX(lastMovePos.x);
      setLogoY(lastMovePos.y);
      break;
    case "background":
      setBgX(lastMovePos.x);
      setBgY(lastMovePos.y);
      setBgPosX(lastMovePos.x);
      setBgPosY(lastMovePos.y);
      break;
  }
  setLastMoveStack((prev) => prev.slice(0, -1));
  if (isMobileView && activeAssetControls) {
    // Keep asset float open after undo to avoid control flicker/closure.
    showMobileFloat("asset");
  }
}, [
  lastMoveStack,
  format,
  isMobileView,
  activeAssetControls,
  showMobileFloat,
  updateIcon,
  updateEmoji,
  updatePortrait,
  setHeadX,
  setHeadY,
  setHead2X,
  setHead2Y,
  setDetailsX,
  setDetailsY,
  setDetails2X,
  setDetails2Y,
  setVenueX,
  setVenueY,
  setSubtagX,
  setSubtagY,
  setLogoX,
  setLogoY,
  setBgX,
  setBgY,
  setBgPosX,
  setBgPosY,
]);

const prepareForMobileTabSwitch = React.useCallback(() => {
  const store = useFlyerState.getState();
  store.setMoveTarget(null);
  store.setSelectedEmojiId(null);
  store.setSelectedPortraitId(null);
  setSelectedEmojiId(null);
  setSelectedPortraitId(null);
  floatFocusLockRef.current = false;
  setFloatingEditorVisible(false);
  setFloatingAssetVisible(false);
  setFloatingBgVisible(false);
  setFloatingLightingVisible(false);
}, [setSelectedEmojiId, setSelectedPortraitId]);

const mobileControlsTabs = (
  <div className="lg:hidden flex justify-center px-3 py-2">
    <div
      data-tour="mobile-tabs"
      className="flex items-center justify-start gap-1.5 overflow-x-auto border-b border-neutral-800 bg-neutral-950/90 px-3 py-2 [scrollbar-width:none] [&::-webkit-scrollbar]:hidden"
      style={{ width: scaledCanvasW, maxWidth: "100%" }}
      onPointerDownCapture={(e) => {
        const t = e.target as Element | null;
        if (t?.closest?.('[data-mobile-float-lock="true"]')) {
          return;
        }
        if (floatingAssetRef.current && floatingAssetRef.current.contains(e.target as Node)) {
          return;
        }
        hideMobileFloats();
      }}
    >
      <button
        type="button"
        onClick={() => {
          prepareForMobileTabSwitch();
          setMobileControlsOpen(true);
          setMobileControlsTab("design");
          if (
            selectedPanel !== "template" &&
            selectedPanel !== "template_backgrounds" &&
            selectedPanel !== "logo" &&
            selectedPanel !== "headline" &&
            selectedPanel !== "head2" &&
            selectedPanel !== "details" &&
            selectedPanel !== "details2" &&
            selectedPanel !== "venue" &&
            selectedPanel !== "subtag" &&
            selectedPanel !== "cinema"
          ) {
            setSelectedPanel("headline");
          }
        }}
        data-tour="mobile-text-tab"
        data-mobile-float-lock="true"
        className={`w-[62px] px-2 py-[3px] text-center text-[9px] font-semibold uppercase tracking-[0.12em] border shrink-0 whitespace-nowrap ${
          mobileControlsTab === "design"
            ? "border-blue-400 text-blue-300 bg-blue-500/10"
            : "border-neutral-700 text-neutral-300 bg-neutral-900/60"
        }`}
      >
        Text
      </button>
      <button
        type="button"
        onClick={() => {
          prepareForMobileTabSwitch();
          setMobileControlsOpen(true);
          setMobileControlsTab("assets");
          if (
            selectedPanel !== "template" &&
            selectedPanel !== "template_backgrounds" &&
            selectedPanel !== "dj_branding" &&
            selectedPanel !== "ai_background" &&
            selectedPanel !== "magic_blend" &&
            selectedPanel !== "background" &&
            selectedPanel !== "bgfx" &&
            selectedPanel !== "icons" &&
            selectedPanel !== "portrait" &&
            selectedPanel !== "project"
          ) {
            setSelectedPanel("background");
          }
        }}
        data-tour="mobile-design-tab"
        data-mobile-float-lock="true"
        className={`w-[62px] px-2 py-[3px] text-center text-[9px] font-semibold uppercase tracking-[0.12em] border shrink-0 whitespace-nowrap ${
          mobileControlsTab === "assets"
            ? "border-blue-400 text-blue-300 bg-blue-500/10"
            : "border-neutral-700 text-neutral-300 bg-neutral-900/60"
        }`}
      >
        Design
      </button>
      <button
        type="button"
        onClick={undoAssetPosition}
        data-mobile-float-lock="true"
        disabled={!lastMoveStack.length}
        className={`px-2 py-[3px] text-[9px] font-semibold uppercase tracking-[0.12em] border shrink-0 whitespace-nowrap ${
          lastMoveStack.length
            ? "border-emerald-400 text-emerald-200 bg-emerald-500/10"
            : "border-neutral-700 text-neutral-500 bg-neutral-900/60 cursor-not-allowed"
        }`}
        title="Undo last position"
      >
        Undo
      </button>
      <button
        type="button"
        onClick={startTour}
        className="px-2 py-[3px] text-[9px] font-semibold uppercase tracking-[0.12em] border border-fuchsia-400/70 text-fuchsia-100 bg-fuchsia-500/20 hover:bg-fuchsia-500/30 shrink-0 whitespace-nowrap"
        title="Start Tour"
      >
        Start Tour
      </button>
      <Link
        href="/pricing"
        onClick={(event) => void handleStudioNavigation(event, "/pricing")}
        className="px-2 py-[3px] text-[9px] font-semibold uppercase tracking-[0.12em] border border-cyan-400/70 text-cyan-100 bg-cyan-500/15 hover:bg-cyan-500/25 shrink-0 whitespace-nowrap"
        aria-label="View Pricing"
      >
        Pricing
      </Link>
    </div>
  </div>
);

React.useEffect(() => {
  if (!activeTextControls) {
    setFloatingEditorVisible(false);
  }
}, [activeTextControls]);

React.useEffect(() => {
  if (typeof window === "undefined") return;
  const update = () => setIsMobileView(window.innerWidth < 1024);
  update();
  window.addEventListener("resize", update);
  return () => window.removeEventListener("resize", update);
}, []);

React.useEffect(() => {
  if (!isMobileView || !isLiveDragging) return;
  const prevBodyOverflow = document.body.style.overflow;
  const prevHtmlOverflow = document.documentElement.style.overflow;
  const prevBodyTouchAction = document.body.style.touchAction;
  const prevHtmlTouchAction = document.documentElement.style.touchAction;
  document.body.style.overflow = "hidden";
  document.documentElement.style.overflow = "hidden";
  document.body.style.touchAction = "none";
  document.documentElement.style.touchAction = "none";
  return () => {
    document.body.style.overflow = prevBodyOverflow;
    document.documentElement.style.overflow = prevHtmlOverflow;
    document.body.style.touchAction = prevBodyTouchAction;
    document.documentElement.style.touchAction = prevHtmlTouchAction;
  };
}, [isLiveDragging, isMobileView]);

React.useEffect(() => {
  if (!hasAssetControls) {
    floatFocusLockRef.current = false;
    setFloatingAssetVisible(false);
  }
}, [hasAssetControls]);

